import React from "react";
import { Menu } from "semantic-ui-react";
import { Auth } from "../../api";
import { useLocation } from "react-router";
import { NavLink } from "react-router-dom";
import "./menu-bar.css";

const MenuBar = () => {
  const { pathname } = useLocation();
  const fullUrl = pathname ? pathname.split("/") : "";
  const currentPath = fullUrl.length > 1 ? fullUrl[1] : "";
  return (
    <div>
      <TitleBar />
      <Menu pointing secondary className="MenuBar">
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/"
          name="Home"
          active={currentPath === ""}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/about-me"
          name="About Mike"
          active={currentPath === "about-me"}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/projects"
          name="Projects"
          active={currentPath === "projects"}
        />
        <Menu.Item
          className="MenuItem"
          as={NavLink}
          to="/contact-me"
          name="Contact"
          active={currentPath === "contact-me"}
        />
      </Menu>
    </div>
  );
};

const TitleBar = () => (
  <div
    style={{
      width: "100%",
      height: "4em",
      display: "flex",
      padding: 24,
      fill: "#000000",
    }}
  >
    {"Photo will be here"}
  </div>
);

function onSignOut() {
  Auth.signOut();
  localStorage.removeItem("emsd");
}

export default MenuBar;
